func (t NotType) ValueFromObject(ctx context.Context, in basetypes.ObjectValue) (basetypes.ObjectValuable, diag.Diagnostics) {
	var diags diag.Diagnostics

	attributes := in.Attributes()

	equalsAttribute, ok := attributes["equals"]

	if !ok {
		diags.AddError(
			"Attribute Missing",
			`equals is missing from object`)

		return nil, diags
	}

	equalsVal, ok := equalsAttribute.(basetypes.ObjectValue)

	if !ok {
		diags.AddError(
			"Attribute Wrong Type",
			fmt.Sprintf(`equals expected to be basetypes.ObjectValue, was: %T`, equalsAttribute))
	}

	inAttribute, ok := attributes["in"]

	if !ok {
		diags.AddError(
			"Attribute Missing",
			`in is missing from object`)

		return nil, diags
	}

	inVal, ok := inAttribute.(basetypes.ObjectValue)

	if !ok {
		diags.AddError(
			"Attribute Wrong Type",
			fmt.Sprintf(`in expected to be basetypes.ObjectValue, was: %T`, inAttribute))
	}

	regexpAttribute, ok := attributes["regexp"]

	if !ok {
		diags.AddError(
			"Attribute Missing",
			`regexp is missing from object`)

		return nil, diags
	}

	regexpVal, ok := regexpAttribute.(basetypes.ObjectValue)

	if !ok {
		diags.AddError(
			"Attribute Wrong Type",
			fmt.Sprintf(`regexp expected to be basetypes.ObjectValue, was: %T`, regexpAttribute))
	}

	if diags.HasError() {
		return nil, diags
	}

	return NotValue{
		Equals: equalsVal,
		In:     inVal,
		Regexp: regexpVal,
		state:  attr.ValueStateKnown,
	}, diags
}

