func (v RegexpValue) ToObjectValue(ctx context.Context) (basetypes.ObjectValue, diag.Diagnostics) {
	var diags diag.Diagnostics

	attributeTypes := map[string]attr.Type{
		"doc":     basetypes.StringType{},
		"pattern": basetypes.StringType{},
	}

	if v.IsNull() {
		return types.ObjectNull(attributeTypes), diags
	}

	if v.IsUnknown() {
		return types.ObjectUnknown(attributeTypes), diags
	}

	objVal, diags := types.ObjectValue(
		attributeTypes,
		map[string]attr.Value{
			"doc":     v.Doc,
			"pattern": v.Pattern,
		})

	return objVal, diags
}

func (v RegexpValue) Equal(o attr.Value) bool {
	other, ok := o.(RegexpValue)

	if !ok {
		return false
	}

	if v.state != other.state {
		return false
	}

	if v.state != attr.ValueStateKnown {
		return true
	}

	if !v.Doc.Equal(other.Doc) {
		return false
	}

	if !v.Pattern.Equal(other.Pattern) {
		return false
	}

	return true
}

func (v RegexpValue) Type(ctx context.Context) attr.Type {
	return RegexpType{
		basetypes.ObjectType{
			AttrTypes: v.AttributeTypes(ctx),
		},
	}
}

